using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a web search tool that fetches and extracts text from URLs.
/// Uses a simple HTML-to-text approach for content extraction.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for a given query and returns a list of result titles and URLs. Use this to find relevant pages about a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            using var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var results = ParseSearchResults(html, maxResults);

            if (results.Count == 0)
            {
                return $"No results found for query: {query}";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"");
            sb.AppendLine();

            for (var i = 0; i < results.Count; i++)
            {
                var (title, link, snippet) = results[i];
                sb.AppendLine($"{i + 1}. {title}");
                sb.AppendLine($"   URL: {link}");
                if (!string.IsNullOrWhiteSpace(snippet))
                {
                    sb.AppendLine($"   {snippet}");
                }
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Try a different query or use FetchPage to read a specific URL.";
        }
    }

    [Description("Fetches a web page and extracts its text content. Use this to read the full content of a page found via SearchWeb.")]
    public async Task<string> FetchPage(
        [Description("The full URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            using var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractText(html);

            // Truncate to avoid overwhelming the context window
            const int maxLength = 4000;
            if (text.Length > maxLength)
            {
                text = string.Concat(text.AsSpan(0, maxLength), "\n\n[Content truncated...]");
            }

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from the page."
                : $"Content from {url}:\n\n{text}";
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html, int maxResults)
    {
        var results = new List<(string, string, string)>();

        var linkMatches = ResultLinkRegex().Matches(html);
        var snippetMatches = SnippetRegex().Matches(html);

        for (var i = 0; i < Math.Min(linkMatches.Count, maxResults); i++)
        {
            var linkMatch = linkMatches[i];
            var rawUrl = WebUtility.HtmlDecode(linkMatch.Groups[1].Value);
            var title = StripHtml(WebUtility.HtmlDecode(linkMatch.Groups[2].Value));

            // DuckDuckGo wraps URLs in a redirect — extract the actual URL
            var actualUrl = ExtractRedirectUrl(rawUrl) ?? rawUrl;
            var snippet = i < snippetMatches.Count
                ? StripHtml(WebUtility.HtmlDecode(snippetMatches[i].Groups[1].Value)).Trim()
                : string.Empty;

            if (!string.IsNullOrWhiteSpace(title) && Uri.IsWellFormedUriString(actualUrl, UriKind.Absolute))
            {
                results.Add((title.Trim(), actualUrl, snippet));
            }
        }

        return results;
    }

    private static string? ExtractRedirectUrl(string url)
    {
        var match = UdduckedRegex().Match(url);
        return match.Success ? Uri.UnescapeDataString(match.Groups[1].Value) : null;
    }

    private static string ExtractText(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Remove HTML tags
        cleaned = TagRegex().Replace(cleaned, " ");
        // Decode HTML entities
        cleaned = WebUtility.HtmlDecode(cleaned);
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return cleaned;
    }

    private static string StripHtml(string input) =>
        TagRegex().Replace(input, string.Empty).Trim();

    [GeneratedRegex(@"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultLinkRegex();

    [GeneratedRegex(@"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"uddg=([^&]+)", RegexOptions.IgnoreCase)]
    private static partial Regex UdduckedRegex();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

