using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking tools for the research agent to organize findings
/// as it researches a topic.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description("Saves a research note with a title and content. Use this to record key findings, facts, or quotes discovered during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note — facts, quotes, or observations")] string content,
        [Description("The source URL where this information was found")] string? sourceUrl = null)
    {
        var note = new Note
        {
            Id = _notes.Count + 1,
            Title = title,
            Content = content,
            SourceUrl = sourceUrl,
            CreatedAt = DateTimeOffset.UtcNow,
        };

        _notes.Add(note);
        return $"Note #{note.Id} saved: \"{title}\"";
    }

    [Description("Lists all saved research notes with their titles and IDs.")]
    public string ListNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Research notes ({_notes.Count} total):");
        sb.AppendLine();

        foreach (var note in _notes)
        {
            sb.AppendLine($"  #{note.Id}: {note.Title}");
            if (!string.IsNullOrWhiteSpace(note.SourceUrl))
            {
                sb.AppendLine($"         Source: {note.SourceUrl}");
            }
        }

        return sb.ToString();
    }

    [Description("Retrieves the full content of a specific note by its ID.")]
    public string GetNote([Description("The note ID to retrieve")] int noteId)
    {
        var note = _notes.Find(n => n.Id == noteId);
        if (note is null)
        {
            return $"Note #{noteId} not found. Use ListNotes to see available notes.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Note #{note.Id}: {note.Title}");
        sb.AppendLine($"Saved at: {note.CreatedAt:u}");
        if (!string.IsNullOrWhiteSpace(note.SourceUrl))
        {
            sb.AppendLine($"Source: {note.SourceUrl}");
        }
        sb.AppendLine();
        sb.AppendLine(note.Content);

        return sb.ToString();
    }

    /// <summary>
    /// Returns all notes formatted for use in a final summary prompt.
    /// </summary>
    public string GetAllNotesFormatted()
    {
        if (_notes.Count == 0)
        {
            return "No research notes were collected.";
        }

        var sb = new StringBuilder();
        sb.AppendLine("=== Collected Research Notes ===");
        sb.AppendLine();

        foreach (var note in _notes)
        {
            sb.AppendLine($"--- Note #{note.Id}: {note.Title} ---");
            sb.AppendLine(note.Content);
            if (!string.IsNullOrWhiteSpace(note.SourceUrl))
            {
                sb.AppendLine($"Source: {note.SourceUrl}");
            }
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

public sealed class Note
{
    public required int Id { get; init; }
    public required string Title { get; init; }
    public required string Content { get; init; }
    public string? SourceUrl { get; init; }
    public DateTimeOffset CreatedAt { get; init; }
