+    /// Returns all notes formatted for use in a final summary prompt.
+    /// </summary>
+    public string GetAllNotesFormatted()
+    {
+        if (_notes.Count == 0)
+        {
+            return "No research notes were collected.";
+        }
+
+        var sb = new StringBuilder();
+        sb.AppendLine("=== Collected Research Notes ===");
