using System.ClientModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// --- Configuration ---
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OpenAI API key via 'AI:ApiKey' in config or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

// --- Register services ---
builder.Services.AddHttpClient<WebSearchTool>();

builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .Use(new OpenAIClient(new ApiKeyCredential(apiKey))
        .GetChatClient(modelId)
        .AsIChatClient()));

builder.Services.AddSingleton<NoteTool>();

using var host = builder.Build();

// --- Resolve services ---
var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteTool = host.Services.GetRequiredService<NoteTool>();
var httpClientFactory = host.Services.GetRequiredService<IHttpClientFactory>();
var httpClient = httpClientFactory.CreateClient(nameof(WebSearchTool));
var webSearchTool = new WebSearchTool(httpClient);

// --- Build tool list ---
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(webSearchTool.SearchWeb),
    AIFunctionFactory.Create(webSearchTool.FetchPage),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.ListNotes),
    AIFunctionFactory.Create(noteTool.GetNote),
};

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? string.Empty;
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Error.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

// --- Phase 1: Research with the agent ---
var researchPrompt = $"""
    You are a research assistant. Your task is to thoroughly research the following topic
    by searching the web and taking structured notes.

    Topic: {topic}

    Instructions:
    1. Search the web for information about this topic using multiple relevant queries.
    2. Fetch and read the most promising pages from the search results.
    3. Save important findings as notes using the SaveNote tool. Each note should capture
       a distinct fact, concept, or piece of evidence. Include the source URL.
    4. Aim to collect at least 3-5 well-sourced notes covering different aspects of the topic.
    5. After gathering sufficient information, list all your notes and confirm you're done.

    Be thorough but focused. Prioritize authoritative sources.
    """;

var researchMessages = new List<ChatMessage>
{
    new(ChatRole.System, researchPrompt),
    new(ChatRole.User, $"Please research this topic: {topic}"),
};

var researchOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = [.. tools],
};

Console.WriteLine();
Console.WriteLine("Phase 1: Researching...");
Console.WriteLine();

var researchResponse = await chatClient.GetResponseAsync(researchMessages, researchOptions);
Console.WriteLine(researchResponse.Text);

// --- Phase 2: Summarize findings ---
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Phase 2: Summarizing findings...");
Console.WriteLine();

var allNotes = noteTool.GetAllNotesFormatted();

var summaryMessages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research summarizer. Given a set of research notes on a topic,
        produce a clear, well-organized summary. Include:

        1. An overview paragraph introducing the topic.
        2. Key findings organized by theme or subtopic.
        3. A brief conclusion.
        4. A list of sources cited.

        Write in a neutral, informative tone. Cite sources by URL where appropriate.
        """),
    new(ChatRole.User, $"""
        Please summarize the following research on "{topic}":

        {allNotes}
        """),
};

var summaryOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
};

await foreach (var update in chatClient.GetStreamingResponseAsync(summaryMessages, summaryOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Research complete. {noteTool.Notes.Count} notes collected.");

